P3803 【模板】多项式乘法（FFT） 递归版迭代版 C++<pre><code>#include&lt;bits/stdc++.h&gt;
#define N 4000005
using namespace std;
char buf[1&lt;&lt;23],*p1=buf,*p2=buf;
#define getchar() (p1==p2&amp;&amp;(p2=(p1=buf)+fread(buf,1,1&lt;&lt;21,stdin),p1==p2)?EOF:*p1++)
inline int read()
{
    int x=0,f=1;
    char ch=getchar();
    while(!isdigit(ch))
    {
        if(ch=='-') f=-1;
        ch=getchar();
    }
    while(isdigit(ch)) x=x*10+(ch^48),ch=getchar();
    return x*f;
}
//自定义复数类
struct Complex
{
    double re,im;
    Complex(double a=0,double b=0):re(a),im(b){}
    Complex operator +(Complex b) {return Complex(re+b.re,im+b.im);}
    Complex operator -(Complex b) {return Complex(re-b.re,im-b.im);}
    Complex operator *(Complex b) {return Complex(re*b.re-im*b.im,im*b.re+re*b.im);}
}tmp[N];
constexpr double PI=acos(-1.0);
//FFT 递归实现
void FFT(Complex* f,int n,int op)
{
    if(n==1) return;
    for(int i=0;i&lt;n;i++) tmp[i]=f[i];
    for(int i=0;i&lt;n;i++)
    {
        if(i&amp;1) f[n/2+i/2]=tmp[i];
        else f[i/2]=tmp[i];
    }
    Complex *g=f,*h=f+n/2;
    FFT(g,n/2,op);
    FFT(h,n/2,op);
    Complex cur(1,0),omega(cos(2*PI/n),sin(2*PI*op/n));
    for(int i=0;i&lt;n/2;i++)
    {
        Complex b=cur*h[i];
        tmp[i]=g[i]+b;
        tmp[n/2+i]=g[i]-b;
        cur=cur*omega;
    }
    for(int i=0;i&lt;n;i++) f[i]=tmp[i];
    return;
}
int n,m,lim;
Complex a[N],b[N];
int main()
{
    n=read(),m=read();
    for(int i=0;i&lt;=n;i++) a[i].re=read();
    for(int i=0;i&lt;=m;i++) b[i].re=read();
    lim=1;
    while(lim&lt;=n+m) lim*=2;
    FFT(a,lim,1);
    FFT(b,lim,1);
    for(int i=0;i&lt;=lim;i++) a[i]=a[i]*b[i];
    FFT(a,lim,-1);
    for(int i=0;i&lt;=n+m;i++) printf("%d ",int(a[i].re/lim+0.5));
    return 0;
}
