#define N 4000005
#define mod 998244353
#define G 3
#define invG 332748118
#define swap(x,y) ((x)^=(y)^=(x)^=(y))
using namespace std;
char buf[1&lt;&lt;23],*p1=buf,*p2=buf;
#define getchar() (p1==p2&amp;&amp;(p2=(p1=buf)+fread(buf,1,1&lt;&lt;21,stdin),p1==p2)?EOF:*p1++)
inline int read()
{
    int x=0,f=1;
    char ch=getchar();
    while(!isdigit(ch))
    {
        if(ch=='-') f=-1;
        ch=getchar();
    }
    while(isdigit(ch)) x=x*10+(ch^48),ch=getchar();
    return x*f;
}
long long qpow(long long a,long long b)
{
    long long res=1;
    while(b)
    {
        if(b&amp;1) res=res*a%mod;
        a=a*a%mod;
        b&gt;&gt;=1;
    }
    return res;
}
int n,m,bit,lim,a[N],b[N],rev[N];
void NTT(int* f,int n,bool op)
{
    for(int i=0;i&lt;n;i++) if(i&lt;rev[i]) swap(f[i],f[rev[i]]);
    for(int len=2,pw,cur;len&lt;=n;len&lt;&lt;=1)
    {
        pw=qpow((op?G:invG),(mod-1)/len);
        for(int l=0,mid,x,y;l&lt;n;l+=len)
        {
            cur=1;
            mid=l+len/2;
            for(int k=l;k&lt;mid;k++)
            {
                x=f[k],y=f[k+len/2];
                f[k]=(x+1ull*cur*y%mod)%mod;
                f[k+len/2]=(x-1ull*cur*y%mod+mod)%mod;
                cur=1ull*cur*pw%mod;
            }
        }
    }
    return;
}
int main()
{
    n=read(),m=read();
    for(int i=0;i&lt;=n;i++) a[i]=read();
    for(int i=0;i&lt;=m;i++) b[i]=read();
    lim=1,bit=0;
    while(lim&lt;=n+m) lim*=2,bit++;
    for(int i=0;i&lt;=lim;i++) rev[i]=(rev[i&gt;&gt;1]&gt;&gt;1)|((i&amp;1)&lt;&lt;(bit-1));
    NTT(a,lim,true);
    NTT(b,lim,true);
    for(int i=0;i&lt;=lim;i++) a[i]=1ull*a[i]*b[i]%mod;
    NTT(a,lim,false);
    int inv=qpow(lim,mod-2);
    for(int i=0;i&lt;=n+m;i++) printf("%lld ",1ll*a[i]*inv%mod);
    return 0;
}
</code></pre> <p>非常不建议使用递归做 NTT，因为如果每次递归算一次快速幂，复杂度会变成 \(O(n\log^2 n)\) 还不如 FFT，而且没多少人会为此写预处理。迭代版就没有这个问题。</p>

P10832 [COTS 2023] 传 Mapa <p>通信题。有 \(n\) 个值域在 \([1,10^9]\) 的键值对，你需要用长度不超过 \(L\) 的 01 串编码和解码这些键值对。\(1\le n\le 100\)，\(L=3000\)。</p> 题解 <p>首先 \([1,10^9]\) 之间的数用二进制表示需要 \(30\) 位，长度限制实际上告诉我们用 \(n\) 个数压缩原来的 \(2n\) 个数。</p> <p>键值对的形式让我们想到函数，我们将键值对看作函数上的点，就可以用拉插刻画这个函数。</p> <p>多项式有两种表达方式，一种是系数表示法，另一种是点值表示法。显然系数表示法过于暴力且麻烦，我们可以钦定 \(f\) 在 \(0\) 到 \(n-1\) 上取值，把 \(f(0)\) 到 \(f(n-1)\) 的值记录下来，这样就省去了点值表示法记录横坐标的开销。</p> <p>时间复杂度 \(O(n^3)\)。</p> 参考代码 C++<pre><code>#include&lt;bits/stdc++.h&gt;
#define N 105
#define B 31
#define mod 1000000007
using namespace std;
long long n,q,x[N],y[N];
string s;
long long qpow(long long a,long long b)
{
    long long res=1;
    while(b)
    {
        if(b&amp;1) res=res*a%mod;
        a=a*a%mod;
        b&gt;&gt;=1;
    }
    return res;
}
long long inv(long long x){return qpow(x,mod-2);}
long long f(long long k)
{
    long long ans=0;
    for(int i=0;i&lt;=n;i++)
    {
        long long res=y[i];
        for(int j=0;j&lt;=n;j++) if(i!=j)
        {
            res=res*((k-x[j]+mod)%mod)%mod*inv((x[i]-x[j]+mod)%mod)%mod;
        }
        ans=(ans+res)%mod;
    }
    return ans;
}
string DtoS(long long x)
{
    string res;
    for(int i=0;i&lt;30;i++) res.push_back(char((x&amp;1)+'0')),x&gt;&gt;=1;
    reverse(res.begin(),res.end());
    return res;
}
long long StoD(string s)
{
    long long res=0;
    for(int i=0;i&lt;s.size();i++)
    {
        res=(res&lt;&lt;1)|(s[i]-'0');
    }
    return res;
}
void solve1()
{
    cin&gt;&gt;n;n--;
    for(int i=0;i&lt;=n;i++) cin&gt;&gt;x[i]&gt;&gt;y[i];
    for(int i=0;i&lt;=n;i++) s+=DtoS(f(i));
    cout&lt;&lt;s.size()&lt;&lt;'\n'&lt;&lt;s&lt;&lt;endl;
    return;
}
void solve2()
{
    int len;
    cin&gt;&gt;n&gt;&gt;q&gt;&gt;len&gt;&gt;s;n--;
    for(int i=0,l=0,r=29;i&lt;=n;i++,l+=30,r+=30)
    {
        x[i]=i;
        y[i]=StoD(s.substr(l,r-l+1));
    }
    while(q--)
    {
        int k;
        cin&gt;&gt;k;
        cout&lt;&lt;f(k)&lt;&lt;'\n';
    }
    return;
}
int main()
{
    int t;
    cin&gt;&gt;t;
    if(t==1) solve1();
    else solve2();
    return 0;
}
</code></pre>
